        { referencia: "João 9:37-38", texto: "Tu já o tens visto... Creio, Senhor! E o adorou." },
        { referencia: "João 9:39", texto: "Eu vim a este mundo para juízo, a fim de que os que não vêem vejam, e os que vêem se tornem cegos." }
